import { useState } from "react";
import axios from "axios";

const API_BASE_URL = "http://localhost:8080/api";

export default function LoginPage({ setPage, setUser }) {
  const [showPass, setShowPass] = useState(false);
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [remember, setRemember] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleLogin = async () => {
    if (!email || !pass) {
      setError("Please fill in all fields");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const response = await axios.post(`${API_BASE_URL}/users/login`, {
        email,
        password: pass
      });

      if (response.data.success) {
        // Store token in localStorage
        const { token, user } = response.data.data;
        localStorage.setItem("token", token);
        localStorage.setItem("user", JSON.stringify(user));

        // Set user in app state
        setUser(user);

        // Redirect based on user role
        if (user.role === "admin") {
          setPage("admin-dashboard");
        } else if (user.role === "chef") {
          setPage("chef-dashboard");
        } else {
          setPage("user-dashboard");
        }
      }
    } catch (err) {
      console.error("Login error:", err);
      setError(err.response?.data?.message || "Login failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-split">
      <div className="auth-visual">
        <img src="https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=700&h=1000&fit=crop" alt="food" />
        <div className="auth-visual-overlay" />
        <div className="auth-visual-text">
          <h2>Discover the art of home cooking.</h2>
          <p>Join thousands of food enthusiasts sharing their secret family recipes every day.</p>
        </div>
      </div>

      <div className="auth-panel">
        <div className="auth-logo">
          <div className="auth-logo-icon">🍽</div>
          <span className="auth-logo-text">RecipeNest</span>
        </div>

        <h1 className="auth-heading">Welcome back</h1>
        <p className="auth-subheading">Please enter your details to sign in to your account.</p>

        {error && (
          <div style={{
            background: "#fee",
            color: "#c33",
            padding: "10px",
            borderRadius: "5px",
            marginBottom: "16px",
            fontSize: "14px"
          }}>
            {error}
          </div>
        )}

        <label className="field-label">Email Address</label>
        <div className="field-wrap">
          <span className="field-icon">✉</span>
          <input
            className="field-input"
            type="email"
            placeholder="name@company.com"
            value={email}
            onChange={e => setEmail(e.target.value)}
            disabled={loading}
          />
        </div>

        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
          <label className="field-label" style={{ margin:0 }}>Password</label>
          <button className="btn-ghost" onClick={() => setPage("forgot-password")}>Forgot password?</button>
        </div>
        <div className="field-wrap">
          <span className="field-icon">🔒</span>
          <input
            className="field-input"
            type={showPass ? "text" : "password"}
            placeholder="••••••••"
            value={pass}
            onChange={e => setPass(e.target.value)}
            disabled={loading}
          />
          <button className="field-eye" onClick={() => setShowPass(v => !v)} disabled={loading}>
            {showPass ? "🙈" : "👁"}
          </button>
        </div>

        <div style={{ display:"flex", alignItems:"center", gap:7, fontSize:13, color:"#555", marginBottom:20 }}>
          <input
            type="checkbox"
            id="remember"
            checked={remember}
            onChange={e => setRemember(e.target.checked)}
            disabled={loading}
          />
          <label htmlFor="remember">Remember me for 30 days</label>
        </div>

        <button
          className="btn-primary"
          onClick={handleLogin}
          disabled={loading}
          style={{ opacity: loading ? 0.7 : 1 }}
        >
          {loading ? "Signing in..." : "Login"}
        </button>

        <div className="auth-divider">or</div>
        <button className="btn-secondary" disabled={loading}>
          <img src="https://www.google.com/favicon.ico" alt="G" width={15} />
          Sign in with Google
        </button>

        <div className="auth-footer">
          Don't have an account? <button onClick={() => setPage("signup")} disabled={loading}>Sign up</button>
        </div>
      </div>
    </div>
  );
}
